// // This module converts a 4-bit input to a 3-bit output. If the input is less than 4, the output is the same as the input. If the input is between 4 and 7, the output is the input minus 2. For inputs of 8 or higher, the output is the input minus 1.
module top_module(
    input [3:0] in_signal,
    output reg [2:0] out_signal
);always @(*) begin
    if (in_signal < 4) begin
        out_signal = in_signal;
    end else if (in_signal < 8) begin
        out_signal = in_signal - 1;
    end else begin
        out_signal = in_signal - 2;
    end
end

endmodule
